    res.setHeader("Access-Control-Allow-Headers", "Content-Type, Authorization, X-Request-ID");
    res.setHeader("Access-Control-Max-Age", "3600");

    // Prevent cache poisoning by varying on Origin
    res.setHeader("Vary", "Origin");
  }
